mapper.select:
SELECT r.user_id AS userId, u.nickname AS nickname, SUM(r.amount) AS amount
FROM u_user_coin_record r
LEFT JOIN u_user u ON u.id = r.user_id AND u.is_deleted = 0
WHERE r.biz_time >= #{start}
  AND r.biz_time < #{end}
  AND r.direction = 1
  AND r.is_deleted = 0
GROUP BY r.user_id, u.nickname
ORDER BY amount DESC
LIMIT #{limit}
